// Remove <think> tags and their content
const response = $json.output;
const cleaned = response.replace(/[\s\S]*?<\/think>/gi, '').trim();

return {
  json: {
    output: cleaned
  }
};

// Parse the escaped JSON string from LLM output
const rawOutput = $json.output || $json.text || $json.response || "";

try {
  // Remove escaped characters and parse
  const cleaned = rawOutput
    .replace(/\\n/g, '')
    .replace(/\\/g, '')
    .trim();

  const parsed = JSON.parse(cleaned);

  return {
    json: {
      is_question: parsed.is_question,
      question_type: parsed.question_type,
      queries: parsed.queries || [],
      notes: parsed.notes || ""
    }
  };
} catch (error) {
  // Fallback if parsing fails
  return {
    json: {
      is_question: false,
      question_type: 0,
      queries: [],
      notes: "Failed to parse LLM output",
      raw_output: rawOutput,
      error: error.message
    }
  };
}

